using System;
namespace MyApp.Models
{
    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string Content { get; set; }
        public DateTime DateSubmitted { get; set; }
    }
}

// Models/Product.cs
using System.Collections.Generic;
namespace MyApp.Models
{
    public class Product
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public virtual ICollection<Review> Reviews { get; set; }
    }
}

// Models/ProductViewModel.cs
using System.Collections.Generic;
namespace MyApp.Models
{
    public class ProductViewModel
    {
        public int ProductId { get; set; }
        public string ProductName { get; set; }
        public IEnumerable<Review> Reviews { get; set; }
    }
}

// Models/ApplicationDbContext.cs
using System.Data.Entity;
namespace MyApp.Models
{
    public class ApplicationDbContext : DbContext
    {
        public ApplicationDbContext() : base("DefaultConnection")
        {
        }
        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }
}

// Controllers/ProductController.cs
using System.Linq;
using System.Web.Mvc;
using MyApp.Models;
namespace MyApp.Controllers
{
    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _db = new ApplicationDbContext();

        public ActionResult Details(int id)
        {
            var product = _db.Products.Find(id);
            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = _db.Reviews
                             .Where(r => r.ProductId == id)
                             .OrderByDescending(r => r.DateSubmitted)
                             .ToList();

            var model = new ProductViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = reviews
            };

            return View(model);
        }
    }
}

// Views/Product/Details.cshtml
@model MyApp.Models.ProductViewModel

<h2>@Model.ProductName Reviews</h2>

@if (Model.Reviews != null && Model.Reviews.Any())
{
    foreach (var review in Model.Reviews)
    {
        <div class="review">
            <p>@Html.Raw(review.Content)</p>
            <small>Submitted on @review.DateSubmitted.ToString("MMM dd, yyyy")</small>
        </div>
    }
}
else
{
    <p>No reviews available for this product.</p>
}